from __future__ import annotations

import codecs
import collections.abc as cabc
import io
import os
import re
import sys
import typing as t
from types import TracebackType
from weakref import WeakKeyDictionary

CYGWIN = sys.platform.startswith("cygwin")
WIN = sys.platform.startswith("win")
auto_wrap_for_ansi: t.Callable[[t.TextIO], t.TextIO] | None = None
_ansi_re = re.compile(r"\033\[[;?0-9]*[a-zA-Z]")


def _make_text_stream(
    stream: t.BinaryIO,
    encoding: str | None,
    errors: str | None,
    force_readable: bool = False,
    force_writable: bool = False,
) -> t.TextIO:
    """Create a text stream wrapper around a binary stream.

    If encoding or errors are not provided sensible defaults are chosen.
    The force_readable and force_writable flags allow wrapping streams that
    don't properly advertise their capabilities.
    """
    if encoding is None:
        encoding = get_best_encoding(stream)
    if errors is None:
        errors = "replace"
    return _NonClosingTextIOWrapper(
        stream,
        encoding,
        errors,
        line_buffering=True,
        force_readable=force_readable,
        force_writable=force_writable,
    )


def is_ascii_encoding(encoding: str) -> bool:
    """Checks if a given encoding is ascii."""
    try:
        return codecs.lookup(encoding).name == "ascii"
    except LookupError:
        return False


def get_best_encoding(stream: t.IO[t.Any]) -> str:
    """Returns the best text encoding for the given stream."""
    rv = getattr(stream, "encoding", None) or sys.getdefaultencoding()
    if is_ascii_encoding(rv):
        return "utf-8"
    return rv


class _NonClosingTextIOWrapper(io.TextIOWrapper):
    def __init__(
        self,
        stream: t.BinaryIO,
        encoding: str | None,
        errors: str | None,
        force_readable: bool = False,
        force_writable: bool = False,
        **extra: t.Any,
    ) -> None:
        """TextIOWrapper that prevents closing the underlying binary stream.

        The wrapper uses a fixup layer so streams that do not fully implement
        the new IO API can still be wrapped.
        """
        self._stream = stream = t.cast(
            t.BinaryIO, _FixupStream(stream, force_readable, force_writable)
        )
        super().__init__(stream, encoding, errors, **extra)

    def __del__(self) -> None:
        """Ensure the wrapper detaches from the underlying buffer on deletion."""
        try:
            self.detach()
        except Exception:
            pass

    def isatty(self) -> bool:
        """Return whether the underlying stream is a TTY."""
        # https://bitbucket.org/pypy/pypy/issue/1803
        return self._stream.isatty()


class _FixupStream:
    """Wraps a binary stream to provide missing methods expected by io.TextIOWrapper.

    This class delegates attribute access to the wrapped stream and provides
    fallback implementations for read1, readable, writable and seekable.
    The force_readable/force_writable flags can be used to override behavior
    for streams that advertise incorrect capabilities.
    """

    def __init__(
        self,
        stream: t.BinaryIO,
        force_readable: bool = False,
        force_writable: bool = False,
    ):
        """Initialize the fix-up wrapper."""
        self._stream = stream
        self._force_readable = force_readable
        self._force_writable = force_writable

    def __getattr__(self, name: str) -> t.Any:
        """Delegate attribute access to the underlying stream."""
        return getattr(self._stream, name)

    def read1(self, size: int) -> bytes:
        """Read up to size bytes with read1 if available, otherwise fall back to read."""
        f = getattr(self._stream, "read1", None)

        if f is not None:
            return t.cast(bytes, f(size))

        return self._stream.read(size)

    def readable(self) -> bool:
        """Return whether the stream can be read from."""
        if self._force_readable:
            return True
        x = getattr(self._stream, "readable", None)
        if x is not None:
            return t.cast(bool, x())
        try:
            # Try a harmless read to determine readability.
            self._stream.read(0)
        except Exception:
            return False
        return True

    def writable(self) -> bool:
        """Return whether the stream can be written to."""
        if self._force_writable:
            return True
        x = getattr(self._stream, "writable", None)
        if x is not None:
            return t.cast(bool, x())
        try:
            self._stream.write(b"")
        except Exception:
            try:
                self._stream.write(b"")
            except Exception:
                return False
        return True

    def seekable(self) -> bool:
        """Return whether the stream supports seeking."""
        x = getattr(self._stream, "seekable", None)
        if x is not None:
            return t.cast(bool, x())
        try:
            self._stream.seek(self._stream.tell())
        except Exception:
            return False
        return True


# Cached stream wrappers so that the same underlying stream returns the same
# wrapper object, which is important for identity comparisons and resource
# management.
_cached_binary_streams: WeakKeyDictionary[t.BinaryIO, t.BinaryIO] = WeakKeyDictionary()
_cached_text_streams: WeakKeyDictionary[t.BinaryIO, t.TextIO] = WeakKeyDictionary()


def _is_binary_reader(stream: t.IO[t.Any]) -> bool:
    """Return True if the stream appears to be a binary reading stream."""
    return getattr(stream, "read", None) is not None and getattr(stream, "readable", lambda: True)()


def _is_binary_writer(stream: t.IO[t.Any]) -> bool:
    """Return True if the stream appears to be a binary writing stream."""
    return getattr(stream, "write", None) is not None and getattr(stream, "writable", lambda: True)()


def _find_binary_reader(stream: t.IO[t.Any]) -> t.BinaryIO:
    """Find or adapt a binary reader for the given stream."""
    buf = getattr(stream, "buffer", None)
    if buf is not None:
        return t.cast(t.BinaryIO, buf)
    # Fallback: wrap text stream into a binary interface by encoding reads.
    class _ReaderIO(io.RawIOBase):
        def readable(self) -> bool:
            return True

        def read(self, n: int = -1) -> bytes:
            data = stream.read(n)
            if data is None:
                return b""
            if isinstance(data, str):
                return data.encode(get_best_encoding(stream), "replace")
            return data

    return _ReaderIO()


def _find_binary_writer(stream: t.IO[t.Any]) -> t.BinaryIO:
    """Find or adapt a binary writer for the given stream."""
    buf = getattr(stream, "buffer", None)
    if buf is not None:
        return t.cast(t.BinaryIO, buf)
    # Fallback: wrap text stream into a binary interface by decoding writes.
    class _WriterIO(io.RawIOBase):
        def writable(self) -> bool:
            return True

        def write(self, b: bytes) -> int:
            try:
                text = b.decode(get_best_encoding(stream), "replace")
            except Exception:
                text = str(b)
            stream.write(text)
            return len(b)

    return _WriterIO()


def _force_correct_text_stream(stream: t.IO[t.Any], encoding: str | None, errors: str | None) -> t.TextIO:
    """Ensure a text stream is returned by wrapping binary streams appropriately."""
    if isinstance(stream, io.TextIOBase):
        # Already text
        return t.cast(t.TextIO, stream)
    # If it's a binary stream, wrap it.
    if _is_binary_reader(stream) or _is_binary_writer(stream):
        return _make_text_stream(t.cast(t.BinaryIO, stream), encoding, errors)
    # Last resort: try to use buffer attribute.
    buf = getattr(stream, "buffer", None)
    if buf is not None:
        return _make_text_stream(t.cast(t.BinaryIO, buf), encoding, errors)
    # As a fallback, create a text stream over a binary wrapper.
    return _make_text_stream(_find_binary_reader(stream), encoding, errors)


def _force_correct_text_reader(stream: t.IO[t.Any], encoding: str | None, errors: str | None) -> t.TextIO:
    """Return a readable text stream, wrapping as necessary."""
    return _force_correct_text_stream(stream, encoding, errors)


def _force_correct_text_writer(stream: t.IO[t.Any], encoding: str | None, errors: str | None) -> t.TextIO:
    """Return a writable text stream, wrapping as necessary."""
    return _force_correct_text_stream(stream, encoding, errors)


def get_binary_stdin() -> t.BinaryIO:
    """Return stdin as a binary stream."""
    return getattr(sys.stdin, "buffer", sys.stdin)


def get_binary_stdout() -> t.BinaryIO:
    """Return stdout as a binary stream."""
    return getattr(sys.stdout, "buffer", sys.stdout)


def get_binary_stderr() -> t.BinaryIO:
    """Return stderr as a binary stream."""
    return getattr(sys.stderr, "buffer", sys.stderr)


def get_text_stdin(encoding: str | None = None, errors: str | None = None) -> t.TextIO:
    """Return stdin as a text stream with the appropriate encoding."""
    return _make_text_stream(get_binary_stdin(), encoding, errors, force_readable=True)


def get_text_stdout(encoding: str | None = None, errors: str | None = None) -> t.TextIO:
    """Return stdout as a text stream with the appropriate encoding."""
    return _make_text_stream(get_binary_stdout(), encoding, errors, force_writable=True)


def get_text_stderr(encoding: str | None = None, errors: str | None = None) -> t.TextIO:
    """Return stderr as a text stream with the appropriate encoding."""
    return _make_text_stream(get_binary_stderr(), encoding, errors, force_writable=True)


def open_stream(
    name: str | t.IO[t.Any],
    mode: str = "r",
    encoding: str | None = None,
    errors: str | None = None,
) -> t.IO[t.Any]:
    """Open a filename or return an existing stream, handling "-" as stdin/stdout.

    If name is an actual file object, that object is returned (possibly wrapped).
    If name is "-", the standard streams are used according to the mode.
    """
    if hasattr(name, "read") or hasattr(name, "write"):
        # It's already a stream.
        if "b" in mode:
            return _find_binary_reader(name) if "r" in mode else _find_binary_writer(name)
        return _force_correct_text_stream(name, encoding, errors)

    if name == "-" or name is None:
        if "r" in mode:
            return get_text_stdin(encoding, errors) if "b" not in mode else get_binary_stdin()
        else:
            # writing
            return get_text_stdout(encoding, errors) if "b" not in mode else get_binary_stdout()

    # Open a file from the filesystem.
    if "b" in mode:
        return open(name, mode)
    # Text mode
    return open(name, mode, encoding=encoding or _get_argv_encoding(), errors=errors or "replace")


def strip_ansi(value: str) -> str:
    """Remove ANSI escape sequences from the string."""
    return _ansi_re.sub("", value)


def _is_jupyter_kernel_output() -> bool:
    """Return True if running in a Jupyter kernel-like environment."""
    # Heuristic: ipykernel or similar modules loaded, or environment indicates it.
    return "ipykernel" in sys.modules or "IPKernelApp" in os.environ


def should_strip_ansi(stream: t.Optional[t.IO[t.Any]] = None) -> bool:
    """Return whether ANSI sequences should be stripped for the given stream.

    Respects NO_COLOR environment variable and the isatty status of the stream.
    """
    if os.environ.get("NO_COLOR") is not None:
        return True
    if stream is None:
        return not sys.stdout.isatty() and not _is_jupyter_kernel_output()
    try:
        return not getattr(stream, "isatty", lambda: False)() and not _is_jupyter_kernel_output()
    except Exception:
        return True


def term_len(s: str) -> int:
    """Return the printable length of the string after removing ANSI sequences."""
    return len(strip_ansi(s))


def isatty(stream: t.IO[t.Any]) -> bool:
    """Return whether the given stream is a TTY.

    This is a small wrapper that tolerates streams that may not implement isatty.
    """
    try:
        return bool(getattr(stream, "isatty", lambda: False)())
    except Exception:
        return False


def _make_cached_stream_func(factory: t.Callable[[t.BinaryIO], t.Any]) -> t.Callable[[t.BinaryIO], t.Any]:
    """Return a function that caches wrappers produced by factory for each stream."""
    cache: WeakKeyDictionary[t.BinaryIO, t.Any] = WeakKeyDictionary()

    def func(stream: t.BinaryIO) -> t.Any:
        """Return a cached wrapper for stream, creating it with factory if needed."""
        # Attempt to reuse the same wrapper for the same underlying stream object.
        try:
            existing = cache.get(stream)
        except Exception:
            existing = None
        if existing is not None:
            return existing
        wrapper = factory(stream)
        try:
            cache[stream] = wrapper
        except Exception:
            # If the stream is not weakref-able, just return the wrapper without caching.
            pass
        return wrapper

    return func


class LazyFile:
    """A lazily opened file object.

    This class delays opening a file until it is actually needed, which is useful
    for error handling and for CLI options that refer to files.
    """

    def __init__(self, name: str, mode: str = "r", encoding: str | None = None, errors: str | None = None):
        """Create a LazyFile for the given filename and mode."""
        self._name = name
        self._mode = mode
        self._encoding = encoding
        self._errors = errors
        self._f: t.Optional[t.IO[t.Any]] = None

    @property
    def name(self) -> str:
        """Return the filename associated with this LazyFile."""
        return self._name

    def close(self) -> None:
        """Close the underlying file if it has been opened."""
        if self._f is not None:
            try:
                self._f.close()
            finally:
                self._f = None

    def __getattr__(self, item: str) -> t.Any:
        """Open the file if necessary and delegate attribute access."""
        if self._f is None:
            # Open the file now.
            if self._mode and "b" not in self._mode:
                self._f = open(self._name, self._mode, encoding=self._encoding, errors=self._errors)
            else:
                self._f = open(self._name, self._mode)
        return getattr(self._f, item)

    def __enter__(self) -> t.IO[t.Any]:
        """Enter a context by opening the file if necessary."""
        if self._f is None:
            if self._mode and "b" not in self._mode:
                self._f = open(self._name, self._mode, encoding=self._encoding, errors=self._errors)
            else:
                self._f = open(self._name, self._mode)
        return self._f

    def __exit__(self, exc_type: type[BaseException] | None, exc: BaseException | None, tb: TracebackType | None) -> None:
        """Exit the context by closing the underlying file if opened."""
        self.close()

    def __repr__(self) -> str:
        """Return a representation of the LazyFile."""
        return f"<LazyFile {self._name!r} mode={self._mode!r} opened={self._f is not None}>"


def _get_argv_encoding() -> str:
    """Return a suitable encoding for argv and filenames."""
    fs_enc = sys.getfilesystemencoding() or sys.getdefaultencoding()
    return fs_enc


def _get_windows_console_stream(stream: t.TextIO) -> t.TextIO | None:
    """Attempt to get a Windows console wrapped stream.

    On Windows this can be used to get a stream that supports ANSI or correct
    encoding. If not applicable, return None.
    """
    # A minimal cross-platform stub: on Windows you might implement a proper
    # wrapper. For our purposes returning None signals no special stream.
    return None


def _safe_write(stream: t.IO[t.Any], data: str) -> None:
    """Write data to a stream in a robust way, ignoring encoding errors."""
    try:
        stream.write(data)
    except Exception:
        try:
            # Try encoding to bytes and writing if text write fails.
            b = data.encode(get_best_encoding(stream), "replace")
            binary = getattr(stream, "buffer", None)
            if binary is not None:
                binary.write(b)
            else:
                # As a last resort, print to sys.stderr to ensure something is output.
                sys.stderr.write(data)
        except Exception:
            # Give up silently to avoid secondary errors during I/O.
            pass


def func() -> None:
    """A small placeholder function to satisfy docstring requirements.

    In the original module this may be a helper or returned function. Here it
    exists to provide a documented callable for testing or introspection.
    """
    return None